import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;
import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;

public class ApiClient {
    private static final String BASE_URL_DEV = "https://api.example.com/dev/users/";
    private static final String BASE_URL_STAGING = "https://api.example.com/staging/users/";
    private static final String BASE_URL_PROD = "https://api.example.com/users/";

    private static Retrofit retrofit;

    public enum Environment {
        DEVELOPMENT,
        STAGING,
        PRODUCTION
    }

    public static ApiService getClient(Environment environment) {
        if (retrofit == null) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BASIC);

            OkHttpClient.Builder clientBuilder = new OkHttpClient.Builder()
                    .addInterceptor(loggingInterceptor);

            String baseUrl;
            switch (environment) {
                case DEVELOPMENT:
                    baseUrl = BASE_URL_DEV;
                    break;
                case STAGING:
                    baseUrl = BASE_URL_STAGING;
                    break;
                default:
                    baseUrl = BASE_URL_PROD;
            }

            retrofit = new Retrofit.Builder()
                    .baseUrl(baseUrl)
                    .addConverterFactory(GsonConverterFactory.create())
                    .client(clientBuilder.build())
                    .build();
        }
        return retrofit.create(ApiService.class);
    }
}

interface ApiService {
    @GET
    Call<List<User>> getUsers(@Url String url);
}

